const body = $json.body ?? {};

const clamp = (value, min, max) => {
  if (!Number.isFinite(value)) {
    return min;
  }

  return Math.min(max, Math.max(min, Math.floor(value)));
};

const slugify = (value) => String(value)
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/(^-|-$)/g, '');

const theme = {
  id: String(body.themeId ?? 'compressed-curiosity'),
  thesis: 'Thirty-to-forty-five second Shorts that explain surprising history, human performance, and everyday science through a fast narrative payoff.',
  publishSlots: ['11:00', '15:00', '19:00'],
};

const laneCatalog = [
  {
    id: 'history-flash',
    label: 'History flash',
    description: 'Unexpected fact, one setup beat, one reversal, one memorable closing line.',
    angles: [
      {
        titleAngle: 'Why Roman concrete survived for centuries',
        seedQuestion: 'Why is Roman concrete still standing when modern concrete often cracks much faster?',
        draftHook: 'Roman concrete had a flaw that made it harder to destroy.',
        riskLevel: 'low',
      },
      {
        titleAngle: 'Why the marathon is such a strange distance',
        seedQuestion: 'Why is a marathon 26.2 miles instead of a clean round number?',
        draftHook: 'The marathon distance exists because one royal family wanted a better view.',
        riskLevel: 'low',
      },
      {
        titleAngle: 'How ancient armies moved faster than most people think',
        seedQuestion: 'How did premodern armies cover distance without engines or modern logistics?',
        draftHook: 'Ancient armies were slow until you look at what they did every single day.',
        riskLevel: 'low',
      },
      {
        titleAngle: 'Why the Romans copied enemy weapons on purpose',
        seedQuestion: 'Why would a dominant empire adopt gear it first saw on opponents?',
        draftHook: 'One reason Rome kept winning was that it was willing to steal good ideas fast.',
        riskLevel: 'low',
      },
      {
        titleAngle: 'How one bad map changed exploration for years',
        seedQuestion: 'How can a single mapping error distort trade and exploration decisions?',
        draftHook: 'A wrong line on a map can shape history longer than the person who drew it.',
        riskLevel: 'low',
      }
    ]
  },
  {
    id: 'human-limits',
    label: 'Human limits',
    description: 'Question about speed, strength, endurance, perception, or survival answered with one clean benchmark.',
    angles: [
      {
        titleAngle: 'How fast elite sprinters really move',
        seedQuestion: 'What does world-class sprint speed actually look like in everyday terms?',
        draftHook: 'At top speed, elite sprinters are moving faster than most people can process in real time.',
        riskLevel: 'low',
      },
      {
        titleAngle: 'What a marathon does to the body',
        seedQuestion: 'What changes inside the body during and after marathon effort?',
        draftHook: 'A marathon does not just make you tired. It forces your whole body into negotiation mode.',
        riskLevel: 'medium',
      },
      {
        titleAngle: 'How long trained divers can hold their breath',
        seedQuestion: 'How much of breath-holding is lung size versus training and chemistry?',
        draftHook: 'The biggest limit in breath-holding is not where most people think it is.',
        riskLevel: 'low',
      },
      {
        titleAngle: 'Why pilots can black out in a turn',
        seedQuestion: 'What does high g-force do to blood flow and perception?',
        draftHook: 'Pilots do not black out because they are weak. They black out because blood has weight.',
        riskLevel: 'medium',
      },
      {
        titleAngle: 'How little sleep starts to impair reaction time',
        seedQuestion: 'At what point does sleep loss meaningfully affect coordination and judgment?',
        draftHook: 'You can feel functional on low sleep long after your reaction time stops agreeing.',
        riskLevel: 'medium',
      }
    ]
  },
  {
    id: 'everyday-systems',
    label: 'Everyday systems',
    description: 'What actually happens when a familiar system works, explained in plain language with one counterintuitive reveal.',
    angles: [
      {
        titleAngle: 'What turbulence really is',
        seedQuestion: 'Why does smooth air suddenly turn rough even when the sky looks calm?',
        draftHook: 'Turbulence feels random from a seat, but the air has a reason every time.',
        riskLevel: 'low',
      },
      {
        titleAngle: 'Why microwaves heat food unevenly',
        seedQuestion: 'Why do some parts of a meal turn boiling while others stay cold?',
        draftHook: 'Your microwave is not broken. It is exposing how energy and geometry fight each other.',
        riskLevel: 'low',
      },
      {
        titleAngle: 'How GPS finds you so precisely',
        seedQuestion: 'How does a phone turn satellite timing into a location dot?',
        draftHook: 'GPS works because your phone solves a timing puzzle at absurd speed.',
        riskLevel: 'low',
      },
      {
        titleAngle: 'Why airplane food tastes different',
        seedQuestion: 'What changes in the cabin make the same meal taste flatter in the air?',
        draftHook: 'Airplane food is not only about bad cooking. Your senses are working under different rules up there.',
        riskLevel: 'low',
      },
      {
        titleAngle: 'What actually happens when you scan a QR code',
        seedQuestion: 'How does a camera turn a blocky square into a destination so quickly?',
        draftHook: 'A QR code looks simple, but your phone has to do more error correction than most people realize.',
        riskLevel: 'low',
      }
    ]
  }
];

const requestedLaneIds = Array.isArray(body.laneIds) && body.laneIds.length > 0
  ? body.laneIds.map((laneId) => String(laneId))
  : laneCatalog.map((lane) => lane.id);

const selectedLanes = laneCatalog.filter((lane) => requestedLaneIds.includes(lane.id));

if (selectedLanes.length === 0) {
  return [{
    json: {
      success: false,
      error: 'No valid laneIds were supplied.',
      availableLaneIds: laneCatalog.map((lane) => lane.id),
    },
  }];
}

const dailyTarget = clamp(Number(body.dailyTarget ?? 3), 1, 6);
const backlogPerLane = clamp(Number(body.backlogPerLane ?? 4), 1, 6);
const recentAngles = new Set(
  (Array.isArray(body.recentAngles) ? body.recentAngles : [])
    .map((value) => String(value).trim().toLowerCase())
    .filter(Boolean)
);

const perLaneBuckets = selectedLanes.map((lane, laneIndex) => {
  const bucket = lane.angles
    .slice(0, backlogPerLane + dailyTarget)
    .filter((angle) => !recentAngles.has(angle.titleAngle.toLowerCase()))
    .map((angle, angleIndex) => ({
      topicId: `${lane.id}-${slugify(angle.titleAngle)}`,
      laneId: lane.id,
      laneLabel: lane.label,
      titleAngle: angle.titleAngle,
      seedQuestion: angle.seedQuestion,
      draftHook: angle.draftHook,
      riskLevel: angle.riskLevel,
      noveltyScore: Number((0.94 - (laneIndex * 0.03) - (angleIndex * 0.04)).toFixed(2)),
      publishSlot: theme.publishSlots[angleIndex % theme.publishSlots.length],
      autoPublishEligible: false,
      operatorMode: 'shadow-review',
    }));

  return {
    laneId: lane.id,
    laneLabel: lane.label,
    items: bucket,
  };
});

const selectedCandidates = [];
let keepSelecting = true;

while (keepSelecting && selectedCandidates.length < dailyTarget) {
  keepSelecting = false;

  for (const bucket of perLaneBuckets) {
    const nextItem = bucket.items.shift();

    if (!nextItem) {
      continue;
    }

    keepSelecting = true;
    selectedCandidates.push(nextItem);

    if (selectedCandidates.length >= dailyTarget) {
      break;
    }
  }
}

const backlogCandidates = perLaneBuckets
  .flatMap((bucket) => bucket.items)
  .sort((left, right) => right.noveltyScore - left.noveltyScore)
  .slice(0, 8);

return [{
  json: {
    success: true,
    workflow: 'vibe-printing-topic-planner',
    generatedAt: new Date().toISOString(),
    request: {
      themeId: theme.id,
      dailyTarget,
      backlogPerLane,
      laneIds: selectedLanes.map((lane) => lane.id),
      recentAnglesCount: recentAngles.size,
    },
    theme,
    selectedCandidates,
    backlogCandidates,
    operatorChecklist: [
      'Validate factual claims before script generation.',
      'Hold medium-risk human performance topics for explicit review.',
      'Avoid reusing near-duplicate hooks inside a 14-day window.',
      'Do not auto-publish until GenSec checks exist downstream.'
    ],
    nextStepSuggestion: 'Use one selected candidate as input to a research-pack or script-generation workflow next.',
  },
}];
